import{_ as t,o as r,c as a,ag as i}from"./chunks/framework.eQLvDOR_.js";const u=JSON.parse('{"title":"jagged-frontier-security","description":"","frontmatter":{"title":"jagged-frontier-security","concept":"能力锯齿边缘与安全护城河","concept_id":"jagged-frontier-security","aliases":["Scaffolding-Moat","Jagged-Frontier"],"sources":["02_Library/Agent_Architecture/[Agent_Architecture] AI Cybersecurity After Mythos.md"],"related_concepts":["[[agent-harness-pattern]]","[[narrow-scope-ai-review]]"],"created_at":"2026-04-21","last_compiled":"2026-04-21"},"headers":[],"relativePath":"wiki/concepts/jagged-frontier-security.md","filePath":"wiki/concepts/jagged-frontier-security.md","lastUpdated":null}'),o={name:"wiki/concepts/jagged-frontier-security.md"};function s(n,e,l,c,g,d){return r(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="能力锯齿边缘与安全护城河-jagged-frontier" tabindex="-1">能力锯齿边缘与安全护城河 (Jagged Frontier) <a class="header-anchor" href="#能力锯齿边缘与安全护城河-jagged-frontier" aria-label="Permalink to &quot;能力锯齿边缘与安全护城河 (Jagged Frontier)&quot;">​</a></h1><h2 id="定义" tabindex="-1">定义 <a class="header-anchor" href="#定义" aria-label="Permalink to &quot;定义&quot;">​</a></h2><p>在 AI 网络安全领域，模型的能力增长并不是随着参数量线性平滑提升的，而是呈现出“锯齿状（Jagged）”：小型模型在某些特定安全任务上的表现可能超越大型顶级模型。</p><h2 id="核心观点-系统即护城河-system-as-moat" tabindex="-1">核心观点：系统即护城河 (System as Moat) <a class="header-anchor" href="#核心观点-系统即护城河-system-as-moat" aria-label="Permalink to &quot;核心观点：系统即护城河 (System as Moat)&quot;">​</a></h2><p>AI 安全的真正价值不在于模型本身的推理能力（Intelligence per token），而在于包裹模型的<strong>脚手架系统（Scaffolding System）</strong>。</p><ul><li><strong>模块化流水线</strong>：安全任务应拆解为：广谱扫描 -&gt; 漏洞检测 -&gt; 自动验证（Triage） -&gt; 补丁生成。每一个环节都可以匹配最合适的模型。</li><li><strong>验证原谕 (Validation Oracles)</strong>：引入编译器异常、ASan（AddressSanitizer）或崩溃原谕作为反馈回路，比追求更聪明的模型更有效。</li><li><strong>广普搜寻 (A Thousand Detectives)</strong>：1000 个廉价模型全量扫描的防御效果，优于 1 个昂贵模型在局部进行的“天才”推断。</li></ul><h2 id="为什么护城河在系统" tabindex="-1">为什么护城河在系统？ <a class="header-anchor" href="#为什么护城河在系统" aria-label="Permalink to &quot;为什么护城河在系统？&quot;">​</a></h2><ol><li><strong>模型不可知论 (Model Agnostic)</strong>：顶级安全架构必须能随时替换后端模型，以应对锯齿边缘的动态变化。</li><li><strong>信任建立</strong>：安全工具的核心是减少误报（False Positives）。这种“特异性（Specificity）”依赖于系统侧的静态/动态分析辅助，而非模型的直觉。</li><li><strong>长期记忆</strong>：安全上下文通常跨越 25 年以上的历史 Bug 记录，这需要系统层面的知识图谱（如 Hindsight）支持。</li></ol><hr><h2 id="实践指南" tabindex="-1">实践指南 <a class="header-anchor" href="#实践指南" aria-label="Permalink to &quot;实践指南&quot;">​</a></h2><ul><li><strong>防御侧</strong>：优先构建基于工具（tools/mcp）的验证链。</li><li><strong>成本策略</strong>：使用小型 MoE 模型（如 GPT-OSS-20b）执行初筛，仅在漏洞验证环节调用高价模型（如 Mythos/Opus）。</li></ul><hr><h2 id="参考链接" tabindex="-1">参考链接 <a class="header-anchor" href="#参考链接" aria-label="Permalink to &quot;参考链接&quot;">​</a></h2><ul><li><a href="/s/webclips/library/Agent_Architecture/Agent_Architecture - AI Cybersecurity After Mythos.html">[Agent_Architecture] AI Cybersecurity After Mythos</a></li></ul>',14)])])}const f=t(o,[["render",s]]);export{u as __pageData,f as default};
